    int n = points.length;
    long count = 0;
    // Use a dictionary to count pairs of points with the same slope
    java.util.HashMap<String, Integer> slopeCounts = new java.util.HashMap<>();

    for (int i = 0; i < n; i++) {
        long x1 = points[i][0];
        long y1 = points[i][1];
        for (int j = i + 1; j < n; j++) {
            long x2 = points[j][0];
            long y2 = points[j][1];
            // Calculate the slope between points i and j
            // To avoid division by zero, we use a tuple (dy, dx) to represent the slope
            long dy = y2 - y1;
            long dx = x2 - x1;
            String slope;
            if (dx == 0) {
                slope = "vertical";
            } else {
                // Simplify the slope by dividing both dy and dx by their greatest common divisor
                long gcd = gcd(Math.abs(dy), Math.abs(dx));
                dy /= gcd;
                dx /= gcd;
                if (dx < 0) {
                    dy = -dy;
                    dx = -dx;
                }
                slope = dy + "," + dx;
            }
            // Increment the count for this slope
            slopeCounts.put(slope, slopeCounts.getOrDefault(slope, 0) + 1);
        }
    }

    // For each pair of points, check how many other pairs have the same slope
    // Each such combination forms a trapezoid
    for (int cnt : slopeCounts.values()) {
        if (cnt >= 2) {
            count += (long) cnt * (cnt - 1) / 2;
        }
    }

    return count;
}

private static long gcd(long a, long b) {
    while (b != 0) {
        long temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}
